/**
 * UI Slice
 *
 * State management for global UI state: toasts, modals, loading, errors.
 *
 * @see specs/006-user-interface.md Section 6.8
 */

import { createSlice } from '@belt/tools';
import type { Toast, ModalState, LoadingState, ErrorState, OptimizerJob } from '../types';

// =============================================================================
// UI Slice State
// =============================================================================

// =============================================================================
// Accessibility State Types
// =============================================================================

export interface AccessibilityState {
  /** User prefers reduced motion (respects OS setting) */
  reducedMotion: boolean;
  /** User prefers high contrast (respects OS setting) */
  highContrast: boolean;
  /** Whether focus ring should be visible (keyboard navigation active) */
  focusVisible: boolean;
  /** Screen reader announcements enabled */
  announcementsEnabled: boolean;
  /** Current focus location for canvas keyboard navigation */
  focusedPmId: string | null;
  /** Last announced message (for debugging) */
  lastAnnouncement: string | null;
}

export interface UiSliceState {
  // Toast notifications
  toasts: Toast[];
  maxToasts: number;

  // Modal state
  modal: ModalState;

  // Loading indicators
  loading: LoadingState;

  // Global error state
  error: ErrorState;

  // Sidebar collapsed
  sidebarCollapsed: boolean;

  // Help panel open
  helpPanelOpen: boolean;

  // Keyboard shortcuts dialog visible
  keyboardShortcutsDialogOpen: boolean;

  // Keyboard shortcuts enabled
  shortcutsEnabled: boolean;

  // Theme
  theme: 'light' | 'dark' | 'system';

  // Optimizer jobs tracking
  optimizerJobs: OptimizerJob[];
  activeJobId: string | null;

  // Connection status
  isOnline: boolean;
  websocketConnected: boolean;

  // Sync status
  lastSyncAt: number | null;
  syncInProgress: boolean;

  // Accessibility (WCAG 2.1 AA compliance)
  accessibility: AccessibilityState;

  // Index signature for MachineState compatibility
  [key: string]: unknown;
}

const initialUiState: UiSliceState = {
  toasts: [],
  maxToasts: 5,
  modal: {
    isOpen: false,
    type: null,
    data: null,
  },
  loading: {
    trains: false,
    pmSchedule: false,
    canvas: false,
    optimizer: false,
  },
  error: {
    message: null,
    code: null,
    details: null,
    timestamp: null,
  },
  sidebarCollapsed: false,
  helpPanelOpen: false,
  keyboardShortcutsDialogOpen: false,
  shortcutsEnabled: true,
  theme: 'system',
  optimizerJobs: [],
  activeJobId: null,
  isOnline: true,
  websocketConnected: false,
  lastSyncAt: null,
  syncInProgress: false,
  // Accessibility defaults (WCAG 2.1 AA)
  accessibility: {
    reducedMotion: false, // Will be synced from OS preference
    highContrast: false, // Will be synced from OS preference
    focusVisible: false, // Shows when keyboard navigation active
    announcementsEnabled: true,
    focusedPmId: null,
    lastAnnouncement: null,
  },
};

let toastIdCounter = 0;

export const uiSlice = createSlice({
  id: 'ui',
  initial: initialUiState,
  cache: { policy: 'session' },
  reducers: {
    // ==========================================================================
    // Toast Notifications
    // ==========================================================================

    addToast: (
      s,
      toast: Omit<Toast, 'id' | 'createdAt'> & { id?: string }
    ) => {
      const state = s as UiSliceState;
      const newToast: Toast = {
        id: toast.id ?? `toast-${++toastIdCounter}`,
        type: toast.type,
        title: toast.title,
        message: toast.message,
        duration: toast.duration ?? 5000,
        dismissible: toast.dismissible ?? true,
        createdAt: Date.now(),
      };

      state.toasts.push(newToast);

      // Trim to max toasts
      if (state.toasts.length > state.maxToasts) {
        state.toasts.shift();
      }
    },

    removeToast: (s, toastId: string) => {
      const state = s as UiSliceState;
      state.toasts = state.toasts.filter((t) => t.id !== toastId);
    },

    clearToasts: (s) => {
      const state = s as UiSliceState;
      state.toasts = [];
    },

    // Convenience toast creators
    showSuccess: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'success',
        title: payload.title,
        message: payload.message,
        duration: 3000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    showError: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'error',
        title: payload.title,
        message: payload.message,
        duration: 8000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    showWarning: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'warning',
        title: payload.title,
        message: payload.message,
        duration: 6000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    showInfo: (s, payload: { title: string; message: string }) => {
      const state = s as UiSliceState;
      state.toasts.push({
        id: `toast-${++toastIdCounter}`,
        type: 'info',
        title: payload.title,
        message: payload.message,
        duration: 5000,
        dismissible: true,
        createdAt: Date.now(),
      });
    },

    // ==========================================================================
    // Modal
    // ==========================================================================

    openModal: (s, payload: { type: string; data?: Record<string, unknown> }) => {
      const state = s as UiSliceState;
      state.modal = {
        isOpen: true,
        type: payload.type,
        data: payload.data ?? null,
      };
    },

    closeModal: (s) => {
      const state = s as UiSliceState;
      state.modal = {
        isOpen: false,
        type: null,
        data: null,
      };
    },

    updateModalData: (s, data: Record<string, unknown>) => {
      const state = s as UiSliceState;
      if (state.modal.isOpen) {
        state.modal.data = { ...state.modal.data, ...data };
      }
    },

    // ==========================================================================
    // Loading
    // ==========================================================================

    setLoading: (s, payload: Partial<LoadingState>) => {
      const state = s as UiSliceState;
      state.loading = { ...state.loading, ...payload };
    },

    startLoading: (s, key: keyof LoadingState) => {
      const state = s as UiSliceState;
      state.loading[key] = true;
    },

    stopLoading: (s, key: keyof LoadingState) => {
      const state = s as UiSliceState;
      state.loading[key] = false;
    },

    clearLoading: (s) => {
      const state = s as UiSliceState;
      state.loading = {
        trains: false,
        pmSchedule: false,
        canvas: false,
        optimizer: false,
      };
    },

    // ==========================================================================
    // Error
    // ==========================================================================

    setError: (
      s,
      payload: { message: string; code?: string; details?: Record<string, unknown> }
    ) => {
      const state = s as UiSliceState;
      state.error = {
        message: payload.message,
        code: payload.code ?? null,
        details: payload.details ?? null,
        timestamp: Date.now(),
      };
    },

    clearError: (s) => {
      const state = s as UiSliceState;
      state.error = {
        message: null,
        code: null,
        details: null,
        timestamp: null,
      };
    },

    // ==========================================================================
    // Layout
    // ==========================================================================

    toggleSidebar: (s) => {
      const state = s as UiSliceState;
      state.sidebarCollapsed = !state.sidebarCollapsed;
    },

    setSidebarCollapsed: (s, collapsed: boolean) => {
      const state = s as UiSliceState;
      state.sidebarCollapsed = collapsed;
    },

    toggleHelpPanel: (s) => {
      const state = s as UiSliceState;
      state.helpPanelOpen = !state.helpPanelOpen;
    },

    setHelpPanelOpen: (s, open: boolean) => {
      const state = s as UiSliceState;
      state.helpPanelOpen = open;
    },

    toggleKeyboardShortcutsDialog: (s) => {
      const state = s as UiSliceState;
      state.keyboardShortcutsDialogOpen = !state.keyboardShortcutsDialogOpen;
    },

    showKeyboardShortcutsDialog: (s) => {
      const state = s as UiSliceState;
      state.keyboardShortcutsDialogOpen = true;
    },

    hideKeyboardShortcutsDialog: (s) => {
      const state = s as UiSliceState;
      state.keyboardShortcutsDialogOpen = false;
    },

    // ==========================================================================
    // Preferences
    // ==========================================================================

    setShortcutsEnabled: (s, enabled: boolean) => {
      const state = s as UiSliceState;
      state.shortcutsEnabled = enabled;
    },

    setTheme: (s, theme: 'light' | 'dark' | 'system') => {
      const state = s as UiSliceState;
      state.theme = theme;
    },

    // ==========================================================================
    // Optimizer Jobs
    // ==========================================================================

    addOptimizerJob: (s, job: OptimizerJob) => {
      const state = s as UiSliceState;
      state.optimizerJobs.push(job);
      state.activeJobId = job.id;
    },

    updateOptimizerJob: (s, job: Partial<OptimizerJob> & { id: string }) => {
      const state = s as UiSliceState;
      const index = state.optimizerJobs.findIndex((j) => j.id === job.id);
      if (index !== -1) {
        state.optimizerJobs[index] = { ...state.optimizerJobs[index], ...job };
      }
    },

    removeOptimizerJob: (s, jobId: string) => {
      const state = s as UiSliceState;
      state.optimizerJobs = state.optimizerJobs.filter((j) => j.id !== jobId);
      if (state.activeJobId === jobId) {
        state.activeJobId = state.optimizerJobs[0]?.id ?? null;
      }
    },

    setActiveJob: (s, jobId: string | null) => {
      const state = s as UiSliceState;
      state.activeJobId = jobId;
    },

    clearCompletedJobs: (s) => {
      const state = s as UiSliceState;
      state.optimizerJobs = state.optimizerJobs.filter(
        (j) => j.status !== 'COMPLETED' && j.status !== 'FAILED'
      );
    },

    // ==========================================================================
    // Connection Status
    // ==========================================================================

    setOnlineStatus: (s, isOnline: boolean) => {
      const state = s as UiSliceState;
      state.isOnline = isOnline;
    },

    setWebsocketConnected: (s, connected: boolean) => {
      const state = s as UiSliceState;
      state.websocketConnected = connected;
    },

    // ==========================================================================
    // Sync Status
    // ==========================================================================

    startSync: (s) => {
      const state = s as UiSliceState;
      state.syncInProgress = true;
    },

    finishSync: (s) => {
      const state = s as UiSliceState;
      state.syncInProgress = false;
      state.lastSyncAt = Date.now();
    },

    // ==========================================================================
    // Accessibility (WCAG 2.1 AA)
    // ==========================================================================

    /** Set reduced motion preference (from OS or user override) */
    setReducedMotion: (s, enabled: boolean) => {
      const state = s as UiSliceState;
      state.accessibility.reducedMotion = enabled;
    },

    /** Set high contrast preference (from OS or user override) */
    setHighContrast: (s, enabled: boolean) => {
      const state = s as UiSliceState;
      state.accessibility.highContrast = enabled;
    },

    /** Set focus visible state (keyboard navigation detected) */
    setFocusVisible: (s, visible: boolean) => {
      const state = s as UiSliceState;
      state.accessibility.focusVisible = visible;
    },

    /** Enable/disable screen reader announcements */
    setAnnouncementsEnabled: (s, enabled: boolean) => {
      const state = s as UiSliceState;
      state.accessibility.announcementsEnabled = enabled;
    },

    /** Set currently focused PM for keyboard navigation */
    setFocusedPm: (s, pmId: string | null) => {
      const state = s as UiSliceState;
      state.accessibility.focusedPmId = pmId;
      // Keyboard navigation detected when focusing via keyboard
      if (pmId !== null) {
        state.accessibility.focusVisible = true;
      }
    },

    /** Clear PM focus */
    clearFocusedPm: (s) => {
      const state = s as UiSliceState;
      state.accessibility.focusedPmId = null;
    },

    /** Record last announcement (for debugging) */
    recordAnnouncement: (s, message: string) => {
      const state = s as UiSliceState;
      state.accessibility.lastAnnouncement = message;
    },

    /** Update multiple accessibility settings at once */
    updateAccessibility: (s, settings: Partial<AccessibilityState>) => {
      const state = s as UiSliceState;
      state.accessibility = { ...state.accessibility, ...settings };
    },

    // ==========================================================================
    // Reset
    // ==========================================================================

    reset: (s) => {
      const state = s as UiSliceState;
      Object.assign(state, initialUiState);
    },
  },
});

// =============================================================================
// Selectors
// =============================================================================

/** Check if any loading is in progress */
export function isAnyLoading(state: UiSliceState): boolean {
  return Object.values(state.loading).some(Boolean);
}

/** Get active optimizer job */
export function selectActiveJob(state: UiSliceState): OptimizerJob | undefined {
  return state.activeJobId
    ? state.optimizerJobs.find((j) => j.id === state.activeJobId)
    : undefined;
}

/** Get running optimizer jobs */
export function selectRunningJobs(state: UiSliceState): OptimizerJob[] {
  return state.optimizerJobs.filter((j) => j.status === 'RUNNING' || j.status === 'PENDING');
}

/** Check if there's an error */
export function hasError(state: UiSliceState): boolean {
  return state.error.message !== null;
}

/** Get visible toasts */
export function selectVisibleToasts(state: UiSliceState): Toast[] {
  const now = Date.now();
  return state.toasts.filter((t) => now - t.createdAt < t.duration);
}

/** Check connection status */
export function isFullyConnected(state: UiSliceState): boolean {
  return state.isOnline && state.websocketConnected;
}

// =============================================================================
// Accessibility Selectors
// =============================================================================

/** Check if reduced motion is preferred */
export function selectReducedMotion(state: UiSliceState): boolean {
  return state.accessibility.reducedMotion;
}

/** Check if high contrast is preferred */
export function selectHighContrast(state: UiSliceState): boolean {
  return state.accessibility.highContrast;
}

/** Check if focus ring should be visible */
export function selectFocusVisible(state: UiSliceState): boolean {
  return state.accessibility.focusVisible;
}

/** Get currently focused PM ID */
export function selectFocusedPmId(state: UiSliceState): string | null {
  return state.accessibility.focusedPmId;
}

/** Check if announcements are enabled */
export function selectAnnouncementsEnabled(state: UiSliceState): boolean {
  return state.accessibility.announcementsEnabled;
}

/** Get full accessibility state */
export function selectAccessibility(state: UiSliceState): AccessibilityState {
  return state.accessibility;
}

/**
 * MMS Notification Tables
 *
 * User notification preferences and notification history for the MMS system.
 * Supports per-user, per-type notification preferences with digest modes.
 *
 * @see specs/004-domain-services.md Section 4.12 (Notification Service)
 * @see specs/007-integration.md Section 7.5 (Email Notifications)
 */

import { relations } from 'drizzle-orm';
import {
  boolean,
  index,
  integer,
  jsonb,
  pgEnum,
  pgTable,
  text,
  timestamp,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { users } from './users';

// =============================================================================
// Enums
// =============================================================================

/**
 * Notification type - categorizes notifications for filtering
 */
export const notificationTypeEnum = pgEnum('notification_type', [
  'DRIFT_ALERT',
  'OVERLOAD_WARNING',
  'PM_REMINDER',
  'BASELINE_PUBLISHED',
  'OPTIMIZER_FAILED',
  'FILE_MISSING',
  'MATERIAL_SHORTAGE',
  'UNAVAILABILITY_PM_CONFLICT',
  'FILE_VALIDATION_FAILED',
  'PROJECTION_ACCURACY_WARNING',
]);

/**
 * Notification severity - determines delivery urgency
 */
export const notificationSeverityEnum = pgEnum('notification_severity', [
  'CRITICAL',
  'HIGH',
  'MEDIUM',
  'LOW',
  'INFO',
]);

/**
 * Digest mode - how notifications are batched for delivery
 */
export const digestModeEnum = pgEnum('digest_mode', [
  'IMMEDIATE',
  'DAILY_DIGEST',
  'WEEKLY_DIGEST',
]);

/**
 * Notification delivery status
 */
export const notificationStatusEnum = pgEnum('notification_status', [
  'PENDING',
  'QUEUED',
  'SENT',
  'FAILED',
  'SUPPRESSED',
]);

// =============================================================================
// Tables
// =============================================================================

/**
 * Notification templates
 *
 * Stores customizable email templates for each notification type.
 * Supports Handlebars-style interpolation ({{variable}}, {{#each}}).
 * Templates can be overridden per-depot or globally.
 *
 * @see specs/007-integration.md Section 7.5.3 (Email Templates)
 */
export const notificationTemplates = pgTable(
  'notification_templates',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    // Template identification
    name: varchar('name', { length: 100 }).notNull().unique(),
    type: notificationTypeEnum('type').notNull(),

    // Template content
    subjectTemplate: varchar('subject_template', { length: 500 }).notNull(),
    bodyHtml: text('body_html').notNull(),
    bodyText: text('body_text'), // Optional plain text version

    // Template metadata
    description: text('description'),
    variables: jsonb('variables').notNull().default([]),

    // Scope
    depotId: uuid('depot_id'), // NULL = global template, otherwise depot-specific override

    // Status
    isActive: boolean('is_active').notNull().default(true),
    version: integer('version').notNull().default(1),

    // Timestamps
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
    createdBy: uuid('created_by'),
    updatedBy: uuid('updated_by'),
  },
  (table) => [
    index('idx_notification_templates_name').on(table.name),
    index('idx_notification_templates_type').on(table.type),
    index('idx_notification_templates_depot').on(table.depotId),
    index('idx_notification_templates_active').on(table.isActive),
  ]
);

/**
 * User notification preferences
 *
 * Stores per-user preferences for each notification type.
 * Includes digest mode settings and granular filters.
 */
export const notificationPreferences = pgTable(
  'notification_preferences',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id, { onDelete: 'cascade' }),

    // Per-type preferences stored as JSONB
    // Format: { [NotificationType]: { enabled: boolean, ...typeSpecificFilters } }
    preferences: jsonb('preferences').notNull().default({
      DRIFT_ALERT: { enabled: true, minSeverity: 'MEDIUM' },
      OVERLOAD_WARNING: { enabled: true, depots: [] },
      PM_REMINDER: { enabled: true, daysBeforeDue: 7 },
      BASELINE_PUBLISHED: { enabled: true },
      OPTIMIZER_FAILED: { enabled: true },
      FILE_MISSING: { enabled: true },
      MATERIAL_SHORTAGE: { enabled: true },
      UNAVAILABILITY_PM_CONFLICT: { enabled: true },
      FILE_VALIDATION_FAILED: { enabled: true },
      PROJECTION_ACCURACY_WARNING: { enabled: true, minSeverity: 'MEDIUM' },
    }),

    // Delivery settings
    digestMode: digestModeEnum('digest_mode').notNull().default('IMMEDIATE'),
    digestTime: varchar('digest_time', { length: 5 }).default('09:00'), // HH:mm format
    timezone: varchar('timezone', { length: 50 }).default('Asia/Hong_Kong'),

    // Email override (uses user.email by default)
    notificationEmail: varchar('notification_email', { length: 255 }),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_notification_preferences_user').on(table.userId),
  ]
);

/**
 * Notification log
 *
 * Records all notifications sent or attempted.
 * Used for auditing, retry management, and digest aggregation.
 */
export const notificationLog = pgTable(
  'notification_log',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    // Recipient
    userId: uuid('user_id').references(() => users.id, { onDelete: 'set null' }),
    recipientEmail: varchar('recipient_email', { length: 255 }).notNull(),

    // Notification metadata
    type: notificationTypeEnum('type').notNull(),
    severity: notificationSeverityEnum('severity').notNull(),
    template: varchar('template', { length: 100 }).notNull(),
    subject: varchar('subject', { length: 500 }),

    // Payload
    data: jsonb('data').notNull(),

    // Delivery status
    status: notificationStatusEnum('status').notNull().default('PENDING'),
    sentAt: timestamp('sent_at', { withTimezone: true }),
    errorMessage: text('error_message'),
    retryCount: integer('retry_count').default(0),
    lastRetryAt: timestamp('last_retry_at', { withTimezone: true }),

    // Digest tracking
    digestBatchId: uuid('digest_batch_id'),
    isDigested: boolean('is_digested').default(false),

    // Related entities (for filtering/grouping)
    trainId: uuid('train_id'),
    depotId: uuid('depot_id'),
    baselineId: uuid('baseline_id'),
    pmScheduleId: uuid('pm_schedule_id'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_notification_log_user').on(table.userId),
    index('idx_notification_log_type').on(table.type),
    index('idx_notification_log_status').on(table.status),
    index('idx_notification_log_created').on(table.createdAt),
    index('idx_notification_log_digest_batch').on(table.digestBatchId),
  ]
);

/**
 * Digest batch
 *
 * Groups notifications for batched delivery.
 * Processed by the notification worker at scheduled times.
 */
export const digestBatches = pgTable(
  'digest_batches',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id, { onDelete: 'cascade' }),

    digestMode: digestModeEnum('digest_mode').notNull(),
    scheduledFor: timestamp('scheduled_for', { withTimezone: true }).notNull(),

    // Status
    status: notificationStatusEnum('status').notNull().default('PENDING'),
    processedAt: timestamp('processed_at', { withTimezone: true }),
    notificationCount: integer('notification_count').default(0),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_digest_batches_user').on(table.userId),
    index('idx_digest_batches_scheduled').on(table.scheduledFor),
    index('idx_digest_batches_status').on(table.status),
  ]
);

// =============================================================================
// Relations
// =============================================================================

export const notificationPreferencesRelations = relations(
  notificationPreferences,
  ({ one }) => ({
    user: one(users, {
      fields: [notificationPreferences.userId],
      references: [users.id],
    }),
  })
);

export const notificationLogRelations = relations(notificationLog, ({ one }) => ({
  user: one(users, {
    fields: [notificationLog.userId],
    references: [users.id],
  }),
}));

export const digestBatchesRelations = relations(digestBatches, ({ one, many }) => ({
  user: one(users, {
    fields: [digestBatches.userId],
    references: [users.id],
  }),
  notifications: many(notificationLog),
}));

export const notificationTemplatesRelations = relations(
  notificationTemplates,
  ({ one }) => ({
    createdByUser: one(users, {
      fields: [notificationTemplates.createdBy],
      references: [users.id],
      relationName: 'createdTemplates',
    }),
    updatedByUser: one(users, {
      fields: [notificationTemplates.updatedBy],
      references: [users.id],
      relationName: 'updatedTemplates',
    }),
  })
);

