     1→/**
     2→ * MMS Notification Worker Processor
     3→ *
     4→ * BullMQ job processor for email notification delivery and digest processing.
     5→ * Handles immediate email sending and scheduled digest batch delivery.
     6→ *
     7→ * Job Types (by name):
     8→ * - send-email: Immediate email delivery
     9→ * - process-digests: Process pending digest batches
    10→ * - retry-failed: Retry failed notifications
    11→ * - cleanup: Clean up old notification logs
    12→ *
    13→ * @see specs/004-domain-services.md Section 4.12
    14→ * @see specs/007-integration.md Section 7.5
    15→ */
    16→
    17→import { logger } from '../../lib/logging/logger';
    18→import { withSpan } from '../../lib/tracing';
    19→import { type WorkerJobContext } from '../index';
    20→import { type NotificationJobData } from '../../lib/queue';
    21→import { getNotificationService } from '../../services/notification';
    22→import { notificationMetrics } from '../../lib/metrics';
    23→
    24→// =============================================================================
    25→// Worker Configuration
    26→// =============================================================================
    27→
    28→const log = logger.child({ worker: 'notification' });
    29→
    30→// =============================================================================
    31→// Job Processor
    32→// =============================================================================
    33→
    34→/**
    35→ * Process notification job
    36→ *
    37→ * Routes to appropriate handler based on job name.
    38→ * All job data must conform to NotificationJobData.
    39→ */
    40→export async function processNotificationJob(
    41→  context: WorkerJobContext<NotificationJobData>
    42→): Promise<unknown> {
    43→  return withSpan('worker.notification.process', async (span) => {
    44→    const { id, name, data } = context;
    45→
    46→    span.setAttribute('jobId', id ?? 'unknown');
    47→    span.setAttribute('jobName', name);
    48→
    49→    log.info({ jobId: id, jobName: name }, 'Processing notification job');
    50→
    51→    // Update progress: starting
    52→    await context.updateProgress({ stage: 'STARTING', percent: 10 });
    53→
    54→    try {
    55→      let result: unknown;
    56→
    57→      switch (name) {
    58→        case 'send-email':
    59→          result = await handleSendEmail(context);
    60→          break;
    61→
    62→        case 'process-digests':
    63→          result = await handleProcessDigests(context);
    64→          break;
    65→
    66→        case 'retry-failed':
    67→          result = await handleRetryFailed(context);
    68→          break;
    69→
    70→        case 'cleanup':
    71→          result = await handleCleanup(context);
    72→          break;
    73→
    74→        default:
    75→          // Treat as generic email send if data has recipients
    76→          if ('recipients' in data && Array.isArray(data.recipients)) {
    77→            result = await handleSendEmail(context);
    78→          } else {
    79→            throw new Error(`Unknown notification job type: ${name}`);
    80→          }
    81→      }
    82→
    83→      // Update progress: complete
    84→      await context.updateProgress({ stage: 'COMPLETE', percent: 100 });
    85→
    86→      return result;
    87→    } catch (error) {
    88→      log.error({ jobId: id, jobName: name, error }, 'Notification job failed');
    89→      throw error;
    90→    }
    91→  });
    92→}
    93→
    94→// =============================================================================
    95→// Job Handlers
    96→// =============================================================================
    97→
    98→/**
    99→ * Handle send-email job
   100→ *
   101→ * Delivers a single email notification immediately.
   102→ */
   103→async function handleSendEmail(
   104→  context: WorkerJobContext<NotificationJobData>
   105→): Promise<{ success: boolean; messageId?: string; error?: string }> {
   106→  const { data } = context;
   107→  const { template, recipients, data: emailData } = data;
   108→  const notificationLogId = (emailData as Record<string, unknown>)['notificationLogId'] as string;
   109→
   110→  await context.log(`Sending email to ${recipients.length} recipient(s)`);
   111→  await context.updateProgress({ stage: 'SENDING', percent: 50 });
   112→
   113→  const notificationService = getNotificationService();
   114→
   115→  // Send to each recipient
   116→  const results: Array<{ success: boolean; messageId?: string; error?: string }> = [];
   117→
   118→  for (const recipient of recipients) {
   119→    const result = await notificationService.deliverEmail(
   120→      notificationLogId,
   121→      template,
   122→      recipient,
   123→      emailData as Record<string, unknown>
   124→    );
   125→    results.push(result);
   126→  }
   127→
   128→  // Check overall success
   129→  const succeeded = results.filter((r) => r.success).length;
   130→  const failed = results.filter((r) => !r.success).length;
   131→
   132→  await context.log(`Email delivery: ${succeeded} succeeded, ${failed} failed`);
   133→
   134→  if (failed > 0) {
   135→    const firstError = results.find((r) => !r.success)?.error;
   136→    return {
   137→      success: succeeded > 0,
   138→      error: failed === recipients.length ? firstError : `${failed}/${recipients.length} failed`,
   139→    };
   140→  }
   141→
   142→  return {
   143→    success: true,
   144→    messageId: results[0]?.messageId,
   145→  };
   146→}
   147→
   148→/**
