// =============================================================================
// Template Rendering
// =============================================================================

/**
 * Render a template with Handlebars-style variable interpolation
 */
function renderTemplate(template: string, data: Record<string, unknown>): string {
  let result = template;

  // Simple variable replacement: {{variable}}
  result = result.replace(/\{\{([^#/}]+)\}\}/g, (match, key) => {
    const trimmedKey = key.trim();
    const value = getNestedValue(data, trimmedKey);
    return value !== undefined ? String(value) : match;
  });

  // Array iteration: {{#each items}}...{{/each}}
  result = result.replace(
    /\{\{#each\s+(\w+)\}\}([\s\S]*?)\{\{\/each\}\}/g,
    (match, arrayKey, itemTemplate) => {
      const array = data[arrayKey];
      if (!Array.isArray(array)) return '';
      return array
        .map((item) => {
          let itemResult = itemTemplate;
          // Replace item properties
          itemResult = itemResult.replace(/\{\{(\w+)\}\}/g, (m, k) => {
            const val = typeof item === 'object' && item !== null ? item[k] : undefined;
            return val !== undefined ? String(val) : m;
          });
          return itemResult;
        })
        .join('');
    }
  );

  return result;
}

/**
 * Get nested property value from object
 */
function getNestedValue(obj: Record<string, unknown>, path: string): unknown {
  const keys = path.split('.');
  let current: unknown = obj;
  for (const key of keys) {
    if (current === null || current === undefined) return undefined;
    if (typeof current !== 'object') return undefined;
    current = (current as Record<string, unknown>)[key];
  }
  return current;
}

